#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int median = A[N / 2];
        int operations = 0;
        for (int i = 0; i < N; i++) {
            operations += abs(A[i] - median);
        }
        printf("%d\n", operations);
        free(A);
    }
    return 0;
}

