code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            int median = A[N / 2];
            int operations = 0;
            for (int i = 0; i < N; i++) {
                operations += Math.abs(A[i] - median);
            }
            System.out.println(operations);
        }
    }
}

